  ('retired-7fec267e-moex-00116', 'retired-7fec267e', 'retired-7fec267e-moex-114-3082b5f1', 'sub-retired-7fec267e-06', NULL, 'single_choice', '甲於自家房屋周圍無圍牆之土地上放置大量廚餘，發出惡臭，廢棄物清理法執行機關 A 市環保 局開立限期清理通知書，命甲10日內清除處理廢棄物。甲屆期仍不為清除，為維持環境衛生， 機關應如何處理？', '["A市環保局只得持續開立限期清理通知書", "A市環保局得請求自來水公司與電力公司對於甲屋為斷水、斷電處置", "A市環保局得直接作成科處新臺幣5,000元以上之怠金", "A市環保局得委託民營廢棄物清理機構代為清除，清除費用由甲負擔"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:00+00:00", "source_pdf_sha1": "08231c21eb42", "answer_pdf_sha1": "647b6f5bbf6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "131", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "一般行政"}'::jsonb, NULL),
