  ('retired-7fec267e-moex-00118', 'retired-7fec267e', 'retired-7fec267e-moex-114-3082b5f1', 'sub-retired-7fec267e-06', NULL, 'single_choice', '有關訴願合法要件之敘述，下列何者正確？', '["甲向主管機關 A 申請核發建造執照，A 遲未核發，甲提起訴願。訴願審議中，A 核發建造執 照，此時應作成訴願不受理之決定", "未成年人未由法定代理人代為提起訴願，應逕為不受理決定", "人民不服課稅處分，應先提起復查，之後方得提起訴願", "行政機關未履行行政契約，人民權利受到損害，得提起課予義務訴願"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:00+00:00", "source_pdf_sha1": "08231c21eb42", "answer_pdf_sha1": "647b6f5bbf6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "131", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "一般行政"}'::jsonb, NULL),
  ('retired-7fec267e-moex-00119', 'retired-7fec267e', 'retired-7fec267e-moex-114-3082b5f1', 'sub-retired-7fec267e-06', NULL, 'single_choice', '下列何者非屬替代訴願之程序？', '["政府採購法之申訴程序", "公務人員保障法之復審程序", "稅捐稽徵法之復查程序", "會計師法之懲戒覆審程序"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:00+00:00", "source_pdf_sha1": "08231c21eb42", "answer_pdf_sha1": "647b6f5bbf6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "131", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "一般行政"}'::jsonb, NULL),
  ('retired-7fec267e-moex-00120', 'retired-7fec267e', 'retired-7fec267e-moex-114-3082b5f1', 'sub-retired-7fec267e-06', NULL, 'single_choice', '依實務見解，關於教師與學校關係，下列敘述何者錯誤？', '["公立各級學校教師與學校間之基礎關係，為行政契約關係", "公私立大學教師資格審定與升等之決定，均為行政處分", "公立學校教師之解聘，其法律性質屬不利益行政處分", "私立大學教師對於解聘，得以教育部之核准為程序標的，提起撤銷訴訟"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:00+00:00", "source_pdf_sha1": "08231c21eb42", "answer_pdf_sha1": "647b6f5bbf6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "131", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "一般行政"}'::jsonb, NULL),
  ('retired-7fec267e-moex-00121', 'retired-7fec267e', 'retired-7fec267e-moex-114-3082b5f1', 'sub-retired-7fec267e-06', NULL, 'single_choice', '甲登記為公職人員選舉候選人，因主管機關認其資格與規定不合而駁回。甲不服提起訴願，遭訴 願駁回，乃提起行政訴訟。甲應提起何種類型之行政訴訟？', '["撤銷訴訟", "課予義務訴訟", "確認訴訟", "一般給付訴訟"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:00+00:00", "source_pdf_sha1": "08231c21eb42", "answer_pdf_sha1": "647b6f5bbf6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "131", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "一般行政"}'::jsonb, NULL),
  ('retired-7fec267e-moex-00122', 'retired-7fec267e', 'retired-7fec267e-moex-114-3082b5f1', 'sub-retired-7fec267e-06', NULL, 'single_choice', '依司法院解釋意旨，有關國家賠償法就有審判或追訴職務之公務員所設之特別規定，下列敘述何 者正確？', '["一、二審判決有罪，三審無罪定讞者，被告得請求賠償", "該特別規定違反平等原則", "法院適用法律見解有誤時，人民得請求賠償", "係基於國家機關功能之差別所設規定"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:00+00:00", "source_pdf_sha1": "08231c21eb42", "answer_pdf_sha1": "647b6f5bbf6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "131", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "一般行政"}'::jsonb, NULL),
  ('retired-7fec267e-moex-00123', 'retired-7fec267e', 'retired-7fec267e-moex-114-3082b5f1', 'sub-retired-7fec267e-06', NULL, 'single_choice', '關於行政損失補償之敘述，下列何者正確？', '["警察不當使用警械，因此對人民所生之財產填補應屬於損失補償", "合法行政處分之廢止，乃是基於公益之追求，無損失補償之問題", "對消防人員破門救火行為所為之補償，屬於合法即時強制行為之損失補償，其補償以金錢為限", "行政私法行為在追求公共任務之履行，故亦有可能成立損失補償"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:00+00:00", "source_pdf_sha1": "08231c21eb42", "answer_pdf_sha1": "647b6f5bbf6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "131", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "一般行政"}'::jsonb, NULL),
  ('retired-7fec267e-moex-00124', 'retired-7fec267e', 'retired-7fec267e-moex-112-adc7838e', 'sub-retired-7fec267e-01', NULL, 'essay', '請從 O.S. Meter 與 C.E. Horn 的執行機關互動模式來評析社區警政之執
